<?php
namespace App\Http\Requests;use Illuminate\Foundation\Http\FormRequest;use Illuminate\Validation\Rule;
final class SellShopItemRequest extends FormRequest{public function authorize(){return true;}public function rules(){return['source_type'=>['required',Rule::in(['stack','instance'])],'character_item_id'=>'nullable|required_if:source_type,stack|prohibited_if:source_type,instance|integer','item_instance_uuid'=>'nullable|required_if:source_type,instance|prohibited_if:source_type,stack|uuid','quantity'=>'required|integer|min:1','zone_id'=>'nullable|integer|min:1','idempotency_key'=>'required|uuid','item_id'=>'prohibited','price'=>'prohibited','unit_gold'=>'prohibited','total_gold'=>'prohibited','gold'=>'prohibited','balance'=>'prohibited','refinement_level'=>'prohibited','rarity'=>'prohibited'];}public function withValidator($v){$v->after(function($v){if($this->input('source_type')==='instance'&&(int)$this->input('quantity')!==1)$v->errors()->add('quantity','Instance quantity must be one.');});}}
